    tmp119 += np.transpose(tmp118, (1, 0))
    del tmp118
    tmp120 = einsum(tmp119, (0, 1), r2.bbb, (2, 1, 3), (3, 2, 0)) * -1
    del tmp119
    tmp121 += np.transpose(tmp120, (0, 2, 1)) * -2
    del tmp120
    r2new.bbb += np.transpose(tmp121, (1, 2, 0))
    r2new.bbb += np.transpose(tmp121, (2, 1, 0)) * -1
    del tmp121
    tmp122 = np.copy(t2.bbbb)
    tmp122 += einsum(t1.bb, (0, 1), t1.bb, (2, 3), (2, 0, 3, 1))
    tmp123 = einsum(r2.bbb, (0, 1, 2), tmp122, (3, 4, 0, 1), (2, 4, 3)) * -1
    del tmp122
    r2new.bbb += einsum(tmp123, (0, 1, 2), v.bbbb.ovov, (1, 3, 2, 4), (4, 3, 0)) * -2
    del tmp123
    r2new.bbb += einsum(tmp89, (0, 1), r2.bbb, (2, 3, 0), (2, 3, 1)) * -2
    del tmp89
    r2new.bbb += einsum(r1.b, (0,), tmp37, (1, 2), (0, 2, 1))
    r2new.bbb += einsum(tmp37, (0, 1), r1.b, (2,), (1, 2, 0)) * -1
    del tmp37

    return {f"r1new": r1new, f"r2new": r2new}

